args.sparql:
SELECT ?park ?parkLabel ?area
WHERE {
  ?park wdt:P31 wd:Q62007;
         wdt:P276 ?location;
         wdt:P2046 ?area.
  ?location wdt:P17 wd:Q30.
  ?park rdfs:label ?parkLabel.
  FILTER (LANG(?parkLabel) = "en")
}
ORDER BY DESC(?area)
LIMIT 1

